"vaisnava sakala asiyachena duyare"',NULL,NULL),('cb.antya.9.196','cb','cb.antya.9','ЧБ Антья 9.196',196,NULL,'govindere ajna haila sabare anite sayane achena, na cahena karo bhite',NULL,NULL),('cb.antya.9.197','cb','cb.antya.9','ЧБ Антья 9.197',197,NULL,'bhaya-yukta haiya sakala bhakta-gana cintite lagila gauracandrera carana',NULL,NULL),('cb.antya.9.198','cb','cb.antya.9','ЧБ Антья 9.198',198,NULL,'ksaneke uthila prabhu sri-bhakta-vatsala balite lagila,—"aye vaisnava-sakala!',NULL,NULL),('cb.antya.9.199','cb','cb.antya.9','ЧБ Антья 9.199',199,NULL,'ahe ahe srinivasa-pandita udara! aji tumi saba ki karila avatara',NULL,NULL),('cb.antya.9.200','cb','cb.antya.9','ЧБ Антья 9.200',200,NULL,'chadiya krsnera naта, krsnera kirtana
ki gaila amare ta'' bujhaha ekhana"',NULL,NULL),('cb.antya.9.201','cb','cb.antya.9','ЧБ Антья 9.201',201,NULL,'mahavakta srinivasa balena,—"gosani! jivera svatantra-sakti mule kichu nai',NULL,NULL),('cb.antya.9.202','cb','cb.antya.9','ЧБ Антья 9.202',202,NULL,'yena karayena, yena balayena isvare se-i aji balilana, kahila tomare"',NULL,NULL),('cb.antya.9.203','cb','cb.antya.9','ЧБ Антья 9.203',203,NULL,'prabhu bale,—"tumi-saba haiya pandita lukaya ye, kene tare karaha vidita"',NULL,NULL),('cb.antya.9.204','cb','cb.antya.9','ЧБ Антья 9.204',204,NULL,'suniya prabhura vakya pandita-srivase haste surya acchadiya mane mane hase',NULL,NULL),('cb.antya.9.205','cb','cb.antya.9','ЧБ Антья 9.205',205,NULL,'prabhu bale,—"ki sanketa kaila hasta diya
